// Scroll to position
$.fn.scrollTo = function( target, options, callback ){
	if(typeof options == 'function' && arguments.length == 2){ callback = options; options = target; }
	var settings = $.extend({
		scrollTarget  : target,
		offsetTop     : 50,
		duration      : 1000,
		easing        : 'swing'
	}, options);
	return this.each(function(){
		var scrollPane = $(this);
		var scrollTarget = (typeof settings.scrollTarget == "number") ? settings.scrollTarget : $(settings.scrollTarget);
		var scrollY = (typeof scrollTarget == "number") ? scrollTarget : scrollTarget.offset().top + scrollPane.scrollTop() - parseInt(settings.offsetTop);
		//$($.browser.webkit ? "body": "html").animate({scrollTop : scrollY }, parseInt(settings.duration), settings.easing, function(){
		$("html").animate({scrollTop : scrollY }, parseInt(settings.duration), settings.easing, function(){
			if (typeof callback == 'function') { callback.call(this); }
		});
	});
}

$.fn.scrollToTop = function () {
	$(this).hide().removeAttr("href");
	if ($(window).scrollTop() != "0") {
		$(this).fadeIn("slow")
	}
	var scrollDiv = $(this);
	$(window).scroll(function () {
		if ($(window).scrollTop() < "400") {
			$(scrollDiv).fadeOut("slow")
		} else {
			$(scrollDiv).fadeIn("slow")
		}
	});
	$(this).click(function () {
		//console.log("scroll to top!");
		$("body").scrollTo(0,{duration: 800});
	});
}

// Get proper window sizes
function viewport() {
	var e = window, a = 'inner';
	if (!('innerWidth' in window )) {
		a = 'client';
		e = document.documentElement || document.body;
	}
	return { width : e[ a+'Width' ] , height : e[ a+'Height' ] };
}

