	//remove chosen class from other labels in group
	chosen_label.parent().find("label").removeClass("active").addClass("disable");
	
	//add chosen class to clicked radio
	$(chosen_label).removeClass("disable").addClass("active");
}

// Aligns items to the centre vertically, in relation to parent container
function alignVertical() {
	$(".align_vert").each(function() {
		thisHeight = $(this).height();
		parentHeight = $(this).parent().height();
		if ($(this).css("border-top-style") !== "none") {
			$(this).css("margin-top",((parentHeight-thisHeight)/2)+"px");
		}
		else $(this).css("padding-top",((parentHeight-thisHeight)/2)+"px");
	});
}

// Converts Things To Title Case
function toTitleCase(str) {
    return str.replace(/\w\S*/g, function(txt){return txt.charAt(0).toUpperCase() + txt.substr(1).toLowerCase();});
}

// Detect IE (returns version of IE or false, if browser is not Internet Explorer)
function detectIE() {
	var ua = window.navigator.userAgent;
	var msie = ua.indexOf('MSIE ');
	if (msie > 0) {
		// IE 10 or older => return version number
		return parseInt(ua.substring(msie + 5, ua.indexOf('.', msie)), 10);
	}
	var trident = ua.indexOf('Trident/');
	if (trident > 0) {
		// IE 11 => return version number
		var rv = ua.indexOf('rv:');
		return parseInt(ua.substring(rv + 3, ua.indexOf('.', rv)), 10);
	}
	var edge = ua.indexOf('Edge/');
	if (edge > 0) {
		// IE 12 => return version number
		return parseInt(ua.substring(edge + 5, ua.indexOf('.', edge)), 10);
	}
	// other browser
	return false;
}

// Hide/show of additional transaction options on homepage
function showTransactions() {
	var initialTextHeight = $(".transactions:not(.additional) li:first-child a > span").outerHeight();
	var hiddenList = $(".transactions.additional, .transactions.wasHidden");
	
	if(hiddenList.hasClass("additional")) {
		// Show
		hiddenList.toggleClass("additional wasHidden");
		hiddenList.find("li").each(function(index) {
			$(this).find("a > span").outerHeight(initialTextHeight);
			$(this).delay(100*index).fadeIn(300);
		}).promise().done(function() {
			$(document).foundation("equalizer", "reflow");
		});
	}
	else {
		// Hide
		hiddenList.slideToggle().promise().done(function() {
			hiddenList.toggleClass("additional wasHidden").removeAttr("style");
			hiddenList.find("li").each(function(index) {
				$(this).hide();
			});
		});
		/*$(hiddenList.find("li").get().reverse()).each(function(index) {
			$(this).find("a > span").outerHeight(initialTextHeight);
			$(this).delay(50*index).fadeOut(300);
		}).promise().done(function() {
			hiddenList.toggleClass("additional wasHidden");
			$(document).foundation("equalizer", "reflow");
		});*/
		
		setTimeout(function(){
			var vertOffset = $(".transactions:visible").parent("div").offset().top;
			if($(window).scrollTop() > vertOffset){
				$("body").scrollTo(vertOffset-10,{duration: 500});
			}
		}, 500);
	}
	
	var button = hiddenList.parent().find(".centre .button");
	button.text(button.text() == "View more transactions" ? "View fewer transactions" : "View more transactions");
}

